module RefModule (
    input clk,
    input rst,
    output [11:0] q
);

    reg [11:0] unused_q_reg;

    always @(posedge clk or posedge rst) begin
        if (rst)
            unused_q_reg <= 12'b000000000000;
        else
            unused_q_reg <= unused_q_reg + 2;
    end

    assign q = unused_q_reg;

endmodule
